import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  it.todo("quote: empty item list → premium 5 G (only processing fee)");
  it.todo("quote: single sword, newcomer first quote → premium 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("quote: single amulet, newcomer first quote → premium 71 G (60 base + 6 first-insurance + 5 fee)");
  it.todo("quote: single staff, newcomer first quote → premium 93 G (80 base + 8 first-insurance + 5 fee)");
  it.todo("quote: single potion, newcomer first quote → premium 49 G (40 base + 4 first-insurance + 5 fee)");
  it.todo("quote: 2 runes, newcomer → premium 60 G (2×25 base + 5 first-insurance + 5 fee)");
  it.todo("quote: 3 runes block, newcomer → premium 71 G (60 block + 6 first-insurance + 5 fee)");
  it.todo("quote: 4 runes, newcomer → premium 115 G (4×25 base + 10 first-insurance + 5 fee)");
  it.todo("quote: 7 runes, newcomer → premium 198 G (7×25=175 base + 17.5 first-insurance + 5 fee = 197.5 → 198 rounded up)");
  it.todo("quote: 2 runes + 1 moonstone, newcomer → premium 88 G (3×25=75 base, no block different types, + 7.5 first-insurance + 5 fee = 87.5 → 88)");
  it.todo("quote: 3 runes + 3 moonstones, newcomer → premium 137 G (60+60=120 two blocks + 12 first-insurance + 5 fee)");
  it.todo("quote: cursed sword enchantment 3, newcomer → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
  it.todo("quote: sword enchantment 5 not cursed, newcomer → premium 145 G (100 base + 30 high-enchantment + 10 first-insurance + 5 fee)");
  it.todo("quote: cursed sword enchantment 5, newcomer → premium 195 G (100 base + 50 curse + 30 high-enchantment + 10 first-insurance + 5 fee)");
  it.todo("quote: sword enchantment 4 not cursed, newcomer → premium 115 G (100 base + 10 first-insurance + 5 fee, no high-enchantment surcharge)");
  it.todo("quote: cursed sword + plain amulet, newcomer → premium 231 G (160 base + 50 curse on sword only + 16 first-insurance + 5 fee)");
  it.todo("quote: loyalty discount, sword, 2 years first quote → premium 95 G (100 base + 10 first-insurance - 20 loyalty + 5 fee)");
  it.todo("quote: follow-up contract, second quote 0 years → premium 100 G (100 base + 10 first-insurance - 15 follow-up + 5 fee)");
  it.todo("quote: long-standing customer second contract integration → second quote premium 160 G (100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first-insurance - 15 follow-up + 5 fee)");
  it.todo("claim: regular sword enchantment 3 steel, damage 500 → payout 400, remainingCap 1600");
  it.todo("claim: rune, damage 200 → payout 100, remainingCap 400");
  it.todo("claim: dragon sword enchantment 9, damage 1000 → payout 400 (50% clause wins over dragon, then deductible), remainingCap 1600");
  it.todo("claim: dragon sword enchantment 5, damage 800 → payout 700 (dragon full reimbursement, no high-ench for claims since <8), remainingCap 1300");
  it.todo("claim: steel sword enchantment 9, damage 1000 → payout 400 (50% high-enchantment clause, then deductible), remainingCap 1600");
  it.todo("claim: dragon sword enchantment 8, damage 1000 → payout 400 (high-ench ≥8 applies, 50% wins over dragon, then deductible), remainingCap 1600");
  it.todo("claim: sword 500 + amulet 300, deductible per item → payout 600 (400+200), remainingCap 2600");
  it.todo("claim: two swords each damaged 500 → payout 800 (400+400, separate deductibles), remainingCap 3200");
  it.todo("claim: more sword damages than swords covered → error");
  it.todo("claim: cursed sword, cap 2000 based on unmodified insurance value → payout 400, remainingCap 1600");
  it.todo("claim: sword + 3 runes block, damage to sword 500 → payout 400, remainingCap 3100 (insurance sum 1750, cap 3500)");
  it.todo("claim: cap exhaustion, two successive claims of 1500 each → first payout 1400 remaining 600, second payout 600 remaining 0");
  it.todo("claim: payout rounding down, steel sword enchantment 8 damage 901 → payout 350 (50% of 901=450.5 - 100 deductible = 350.5 → 350), remainingCap 1650");
  it.todo("error: unknown item type in quote → throws error");
  it.todo("error: damage entry for item not in policy → throws error");
  it.todo("error: negative damage amount → throws error");
});

export function processScenario(input: unknown): unknown {
  return { results: [] };
}

