const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function roundUp(value: number): number {
  return Math.ceil(Math.round(value * 1000) / 1000);
}

interface Step {
  items: { type: string }[];
}

export function processScenario(input: { steps: Step[] }): { results: { premium: number }[] } {
  const items = input.steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: PROCESSING_FEE }] };
  }
  let basePremium = 0;
  for (const item of items) {
    basePremium += BASE_PREMIUMS[item.type] ?? 0;
  }
  const premium = roundUp(basePremium + basePremium * 0.1 + PROCESSING_FEE);
  return { results: [{ premium }] };
}

