input.newString:
const PROCESSING_FEE = 5;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function roundUp(value: number): number {
  return Math.ceil(Math.round(value * 1000) / 1000);
}

function calculateBasePremium(items: { type: string }[]): number {
  const componentCounts: Record<string, number> = {};
  let total = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += BASE_PREMIUMS[item.type] ?? 0;
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 3) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }

  return total;
}

interface Step {
  items: { type: string }[];
}

export function processScenario(input: { steps: Step[] }): { results: { premium: number }[] } {
  const items = input.steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: PROCESSING_FEE }] };
  }
  const basePremium = calculateBasePremium(items);
  const premium = roundUp(basePremium + basePremium * 0.1 + PROCESSING_FEE);
  return { results: [{ premium }] };
}

