input.newString:
const PROCESSING_FEE = 5;
const BLOCK_PREMIUM = 60;
const CURSE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
}

function roundUp(value: number): number {
  return Math.ceil(Math.round(value * 1000) / 1000);
}

function calculateBasePremium(items: Item[]): number {
  const componentCounts: Record<string, number> = {};
  let total = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += BASE_PREMIUMS[item.type] ?? 0;
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 3) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }

  return total;
}

function calculateItemSpecificSurcharges(items: Item[]): number {
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) continue;
    const base = BASE_PREMIUMS[item.type] ?? 0;
    if (item.cursed) total += base * CURSE_RATE;
    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
      total += base * HIGH_ENCHANTMENT_RATE;
    }
  }
  return total;
}

interface Step {
  items: Item[];
}

export function processScenario(input: { steps: Step[] }): { results: { premium: number }[] } {
  const items = input.steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: PROCESSING_FEE }] };
  }
  const basePremium = calculateBasePremium(items);
  const itemSurcharges = calculateItemSpecificSurcharges(items);
  const premium = roundUp(basePremium + itemSurcharges + basePremium * 0.1 + PROCESSING_FEE);
  return { results: [{ premium }] };
}

